mapper.select:
SELECT id, reagent_id, batch_number, production_date, expiry_date, opened_expiry_days, opened_date, initial_quantity, current_quantity, unit_price, storage_location, supplier_id, status, remark, create_time FROM reagent_batch
AND reagent_id = #{reagentId}
AND batch_number LIKE CONCAT('%', #{batchNumber}, '%')
AND (batch_number LIKE CONCAT('%', #{keyword}, '%') OR reagent_id IN ( SELECT id FROM reagent WHERE name LIKE CONCAT('%', #{keyword}, '%') ))
AND status = #{status}
ORDER BY id DESC
